PREFIX dbo: <http://dbpedia.org/ontology/> PREFIX dbr: <http://dbpedia.org/resource/> 
SELECT DISTINCT ?governor WHERE { dbr:Wyoming dbo:governor ?governor } 
UNION 
{ SELECT ?film WHERE { ?film dbo:director dbr:Tim_Burton ; dbo:budget ?budget } ORDER BY DESC(?budget) LIMIT 1 } 
UNION 
{ SELECT ?borough WHERE { ?borough dbo:governmentType dbr:Borough_(New_York_City) } }

PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?answer
WHERE
  {   { <http://dbpedia.org/resource/Netherlands>
                  <http://dbpedia.org/ontology/leader>  ?answer .
        ?answer   rdf:type              <http://dbpedia.org/ontology/Royalty>
      }
    UNION
      { ?answer  rdf:type              <http://dbpedia.org/ontology/Monarch> ;
                 <http://dbpedia.org/ontology/spouse>  ?spouse
          { ?spouse  <http://dbpedia.org/ontology/birthPlace>  <http://dbpedia.org/resource/Germany> }
        UNION
          { ?spouse  <http://dbpedia.org/ontology/birthPlace>  ?place .
            ?place   <http://dbpedia.org/ontology/country>  <http://dbpedia.org/resource/Germany>
          }
      }
    UNION
      { ?answer  rdf:type              <http://dbpedia.org/ontology/PoliticalParty> ;
                 <http://dbpedia.org/ontology/country>  <http://dbpedia.org/resource/Greece> ;
                 <http://dbpedia.org/ontology/ideology>  <http://dbpedia.org/resource/Pro-Europeanism>
      }
  }

PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?result WHERE {
  {
    # Countries that have places with more than two caves
    ?cave dbo:location ?place .
    ?place dbo:country ?result .
    ?result a dbo:Country .
  }
  UNION
  {
    # Countries with more than ten caves directly
    ?cave dbo:location ?result .
    ?result a dbo:Country .
  }
  UNION
  {
    # Countries with places referencing country directly
    ?cave dbo:location ?loc .
    ?loc dbo:country ?result .
    ?result a dbo:Country .
  }
  UNION
  {
    # Caves with more than 3 entrances
    ?result a dbo:Cave ;
      <http://dbpedia.org/property/entranceCount> ?entrance .
    FILTER(?entrance > 3)
  }
}
GROUP BY ?result
HAVING (
  (EXISTS {
    SELECT ?country WHERE {
      ?cave dbo:location ?place .
      ?place dbo:country ?country .
      ?country a dbo:Country .
    }
    GROUP BY ?country
    HAVING(COUNT(?cave) > 2 && ?country = ?result)
  }) ||
  (EXISTS {
    SELECT ?country WHERE {
      { ?cave dbo:location ?country . }
      UNION
      { ?cave dbo:location ?loc . ?loc dbo:country ?country . }
      ?country a dbo:Country .
    }
    GROUP BY ?country
    HAVING(COUNT(?cave) > 10 && ?country = ?result)
  }) ||
  (EXISTS {
    ?result a dbo:Cave ;
      <http://dbpedia.org/property/entranceCount> ?entrance .
    FILTER(?entrance > 3 && ?result = ?result)
  })
)

