PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?answer
WHERE
  {   { ?film    rdf:type              <http://dbpedia.org/ontology/Film> ;
                 <http://dbpedia.org/ontology/country>  <http://dbpedia.org/resource/Spain> ;
                 <http://dbpedia.org/ontology/producer>  <http://dbpedia.org/resource/Benicio_del_Toro> ;
                 <http://dbpedia.org/ontology/starring>  ?answer .
        ?answer  rdf:type              <http://dbpedia.org/ontology/Person>
      }
    UNION
      { PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
        PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
        PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
        PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

        SELECT  (COUNT(DISTINCT ?film) AS ?answer)
        WHERE
          { ?film  rdf:type              <http://dbpedia.org/ontology/Film> ;
                   <http://dbpedia.org/ontology/starring>  <http://dbpedia.org/resource/Leonardo_DiCaprio>
          }
      }
    UNION
      { ?film  rdf:type              <http://dbpedia.org/ontology/Film> ;
               <http://dbpedia.org/ontology/producer>  <http://dbpedia.org/resource/Hal_Roach>
        BIND(?film AS ?answer)
      }
  }

