  res:Tom_Hanks dbo:spouse res:Rita_Wilson .
}
SELECT DISTINCT ?wifeLincoln WHERE {
  res:Abraham_Lincoln dbo:spouse ?wifeLincoln .
}

PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?person
WHERE
  {   { FILTER ( false ) }
    UNION
      { ?person  rdf:type              <http://dbpedia.org/ontology/Actor> .
        ?movie   rdf:type              <http://dbpedia.org/ontology/Film> ;
                 <http://dbpedia.org/ontology/starring>  ?person
      }
    UNION
      { ?person  <http://dbpedia.org/ontology/knownFor>  <http://dbpedia.org/resource/Manhattan_Project> ;
                 rdf:type              <http://dbpedia.org/ontology/Scientist> ;
                 <http://dbpedia.org/ontology/knownFor>  <http://dbpedia.org/resource/Nobel_Peace_Prize>
      }
  }
GROUP BY ?person
ORDER BY DESC(COUNT(DISTINCT ?movie))
LIMIT   1

PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?writer
WHERE
  {   { ?writer  rdf:type              <http://dbpedia.org/ontology/Writer> ;
                 <http://dbpedia.org/ontology/award>  <http://dbpedia.org/resource/Nobel_Prize_in_Literature>
      }
    UNION
      { PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
        PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
        PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
        PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

        SELECT  ?poet
        WHERE
          { ?poet  <http://dbpedia.org/ontology/occupation>  <http://dbpedia.org/resource/Poet> .
            ?book  <http://dbpedia.org/ontology/author>  ?poet ;
                   rdf:type              <http://dbpedia.org/ontology/Book>
          }
        GROUP BY ?poet
        ORDER BY DESC(COUNT(?book))
        LIMIT   1
      }
    UNION
      { ?writer  rdf:type  <http://dbpedia.org/ontology/Writer>
          { ?writer  <http://dbpedia.org/ontology/almaMater>  ?edu }
        UNION
          { ?writer  <http://dbpedia.org/ontology/education>  ?edu }
          { ?edu  <http://dbpedia.org/ontology/city>  <http://dbpedia.org/resource/Istanbul> }
        UNION
          { ?edu  <http://dbpedia.org/property/city>  <http://dbpedia.org/resource/Istanbul> }
      }
  }

