PREFIX yago: <http://dbpedia.org/class/yago/>
PREFIX dbp: <http://dbpedia.org/property/>
PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX res: <http://dbpedia.org/resource/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?answer WHERE {
  {
    BIND("Was Margaret Thatcher a chemist?" AS ?question)
    BIND(
      IF(EXISTS {
        res:Margaret_Thatcher dbo:profession res:Chemist
      }, "Yes", "No") AS ?answer
    )
  }
  UNION
  {
    BIND("Which U.S. states possess gold minerals?" AS ?question)
    SELECT DISTINCT ?answer WHERE {
      ?answer rdf:type yago:WikicatStatesOfTheUnitedStates ;
              dbp:mineral ?mineral .
      FILTER regex(?mineral, "gold", "i")
    }
  }
  UNION
  {
    BIND("What is in a chocolate chip cookie?" AS ?question)
    SELECT DISTINCT ?answer WHERE {
      res:Chocolate_chip_cookie dbo:ingredient ?answer
    }
  }
}

