PREFIX dbo: <http://dbpedia.org/ontology/> 
PREFIX res: <http://dbpedia.org/resource/> 
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

SELECT DISTINCT ?answer WHERE {
  { 
    ?moon dbo:satelliteOf res:Jupiter ; dbo:mass ?mass .
    FILTER NOT EXISTS {
      ?other dbo:satelliteOf res:Jupiter ; dbo:mass ?otherMass .
      FILTER(?otherMass < ?mass)
    }
    BIND(?mass AS ?answer)
  }
  UNION
  {
    res:Titanic_(1997_film) dbo:musicComposer ?composer .
    BIND(?composer AS ?answer)
  }
  UNION
  {
    ?launchPad rdf:type dbo:LaunchPad ; dbo:operator res:NASA .
    BIND(?launchPad AS ?answer)
  }
}

