              <http://dbpedia.org/ontology/birthDate>  ?date ;
              <http://dbpedia.org/ontology/highlights>  ?h
        FILTER regex(str(?h), "MVP", "i")
      }
    UNION
      { ?uri  rdf:type              <http://dbpedia.org/ontology/SoccerClub> ;
