PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?river
WHERE
  {   { ?river  rdf:type              <http://dbpedia.org/ontology/River> .
        ?lake   rdf:type              <http://dbpedia.org/ontology/Lake> ;
                <http://dbpedia.org/ontology/inflow>  ?river ;
                <http://dbpedia.org/ontology/country>  <http://dbpedia.org/resource/Germany>
      }
    UNION
      { ?river  rdf:type  <http://dbpedia.org/ontology/River> }
    UNION
      { ?lake  rdf:type              <http://dbpedia.org/ontology/Lake> ;
               <http://dbpedia.org/ontology/country>  <http://dbpedia.org/resource/Denmark>
        BIND(?lake AS ?river)
      }
  }
ORDER BY DESC(( ?river = ?river ))
LIMIT   100

